#!/usr/bin/env python3
"""
Comprehensive test of the validate_key fix.
"""

import numpy as np
from dask.core import validate_key

def test_valid_keys():
    """Test that valid keys still work."""
    print("=== Testing Valid Keys ===")

    valid_cases = [
        1,
        "hello", 
        1.5,
        b"bytes",
        (),
        (1,),
        ("x", 1),
        ("x", 1, "y", 2.5),
        ("nested", ("tuple", 1)),
    ]

    for case in valid_cases:
        try:
            validate_key(case)
            print(f"✓ validate_key({case!r}) passed")
        except Exception as e:
            print(f"✗ validate_key({case!r}) failed unexpectedly: {e}")

def test_invalid_non_tuple_keys():
    """Test that invalid non-tuple keys still give original error."""
    print("\n=== Testing Invalid Non-Tuple Keys ===")

    invalid_cases = [
        [1, 2],
        {1, 2},
        {"a": 1},
        object(),
    ]

    for case in invalid_cases:
        try:
            validate_key(case)
            print(f"✗ validate_key({case!r}) should have failed")
        except TypeError as e:
            expected_msg = f"Unexpected key type {type(case)} (value: {case!r})"
            if str(e) == expected_msg:
                print(f"✓ validate_key({case!r}) failed with expected message")
            else:
                print(f"? validate_key({case!r}) failed with different message: {e}")
        except Exception as e:
            print(f"? validate_key({case!r}) failed with unexpected error type: {e}")

def test_invalid_tuple_components():
    """Test that tuples with invalid components give improved error messages."""
    print("\n=== Testing Invalid Tuple Components ===")

    # Single invalid component
    test_cases = [
        ((1, np.int64(2)), "index 1"),
        ((np.float64(1.5), 2), "index 0"),
        (("x", 1, [1, 2]), "index 2"),
        (({1, 2},), "index 0"),
    ]

    for case, expected_index_info in test_cases:
        try:
            validate_key(case)
            print(f"✗ validate_key({case!r}) should have failed")
        except TypeError as e:
            if "Invalid key component" in str(e) and expected_index_info in str(e):
                print(f"✓ validate_key({case!r}) failed with improved message: {e}")
            elif "Invalid key component" in str(e):
                print(f"? validate_key({case!r}) failed with component error but different index: {e}")
            else:
                print(f"? validate_key({case!r}) failed with unexpected message: {e}")
        except Exception as e:
            print(f"? validate_key({case!r}) failed with unexpected error type: {e}")

def test_first_invalid_component():
    """Test that only the first invalid component is reported."""
    print("\n=== Testing First Invalid Component Reporting ===")

    # Tuple with multiple invalid components - should report first one
    case = (np.int64(1), [1, 2], {3, 4})
    try:
        validate_key(case)
        print(f"✗ validate_key({case!r}) should have failed")
    except TypeError as e:
        if "Invalid key component at index 0" in str(e):
            print(f"✓ validate_key({case!r}) correctly reports first invalid component: {e}")
        else:
            print(f"? validate_key({case!r}) error: {e}")

if __name__ == "__main__":
    test_valid_keys()
    test_invalid_non_tuple_keys()
    test_invalid_tuple_components()
    test_first_invalid_component()

